// ─── CONFIG BASE + OVERRIDES DEL DASHBOARD ───
// Funciona desde Schedule Trigger Y desde webhook del dashboard.
// El dashboard puede sobrescribir HASHTAG_OFFSET, HASHTAGS_BATCH, RESULTS_PER_HASHTAG.
// El resto (tokens, sheet, hashtags, filtros) siempre viene del config base.

const input = $input.first().json;

// Si el input tiene 'body', vino del webhook del dashboard
const webhookBody = input.body || {};

// ── CONFIG BASE (fallback / valores por defecto) ──
const config = {
  APIFY_TOKEN: 'apify_api_REPLACED_BY_ANTIGRAVITY_FOR_SECURITY',
  SHEET_ID: '148Q0yaGAF5Y23rQPUMy7mgQbYFhaql1CVUfciWNE_PE',
  HASHTAGS_BATCH: '3',
  RESULTS_PER_HASHTAG: '30',
  MAX_PROFILES_TO_ENRICH: '40',
  MIN_FOLLOWERS: '300',
  MAX_FOLLOWERS: '500000',
  ALL_HASHTAGS_JSON: '["rockargentino","bandarock","metalargentino","bluesargentino","jazzargentino","indieargentino","punkargentino","folkargentino","rockchileno","metalchile","indiechile","rockmexico","bandamexico","metalmexico","indiemexico","jazzmexico","rockcolombia","indiecolombia","metalcolombia","rockuruguay","rockperu","rockvenezuela","rockcr","rockparaguay","indielatam","alternativolatam","postpunklatam","shoegazelatam","grungelatam","hardrocklat","progresivometal","newwavelatam"]',
  HASHTAG_OFFSET: '0'
};

// ── OVERRIDES DE PARÁMETROS DEL DASHBOARD ──
if (webhookBody.offset !== undefined && parseInt(webhookBody.offset) >= 0) {
  config.HASHTAG_OFFSET = String(parseInt(webhookBody.offset));
  console.log(`📱 Dashboard sobrescribió offset: ${config.HASHTAG_OFFSET}`);
}

if (webhookBody.hashtags_batch && parseInt(webhookBody.hashtags_batch) > 0) {
  config.HASHTAGS_BATCH = String(parseInt(webhookBody.hashtags_batch));
  console.log(`📱 Dashboard sobrescribió batch: ${config.HASHTAGS_BATCH}`);
}

if (webhookBody.results_per_hashtag && parseInt(webhookBody.results_per_hashtag) > 0) {
  config.RESULTS_PER_HASHTAG = String(parseInt(webhookBody.results_per_hashtag));
  console.log(`📱 Dashboard sobrescribió results: ${config.RESULTS_PER_HASHTAG}`);
}

const source = webhookBody.offset !== undefined ? 'Dashboard (webhook)' : 'Schedule Trigger / Manual';
console.log(`🔧 Fuente: ${source}`);
console.log(`📋 Config final: offset=${config.HASHTAG_OFFSET}, batch=${config.HASHTAGS_BATCH}, results=${config.RESULTS_PER_HASHTAG}`);

return [{ json: config }];

const cfg = $input.first().json;
const allHashtags = JSON.parse(cfg.ALL_HASHTAGS_JSON);
const batchSize = parseInt(cfg.HASHTAGS_BATCH) || 3;
const offset = parseInt(cfg.HASHTAG_OFFSET) || 0;

const batch = allHashtags.slice(offset, offset + batchSize);
const nextOffset = (offset + batchSize) >= allHashtags.length ? 0 : offset + batchSize;

console.log(`📋 Hashtags en este run: ${batch.join(', ')}`);
console.log(`💡 Próximo offset a usar: ${nextOffset} (de ${allHashtags.length} hashtags totales)`);

return [{
  json: {
    ...cfg,
    hashtags_batch: batch,
    next_offset: nextOffset,
    total_hashtags: allHashtags.length
  }
}];

const items = $input.all();
const cfg = $('⚙️ Config + Override Dashboard').first().json;
const maxToEnrich = parseInt(cfg.MAX_PROFILES_TO_ENRICH) || 40;

const seen = new Set();
const usernames = [];
let rawCount = 0;

for (const item of items) {
  const data = item.json;
  const posts = Array.isArray(data) ? data : [data];

  for (const post of posts) {
    rawCount++;
    const username = post.ownerUsername || post.username || (post.author && post.author.username);
    if (username && typeof username === 'string' && username.length > 0) {
      const lower = username.toLowerCase().trim();
      if (!seen.has(lower)) {
        seen.add(lower);
        usernames.push(username.trim());
      }
    }
  }
}

const limited = usernames.slice(0, maxToEnrich);

const USERNAME_EXCLUDE = [
  'shop', 'store', 'tienda', 'ropa', 'clothing', 'boutique',
  'bar_', '_bar', 'pub_', 'cerveza', 'beer',
  'estudio', 'studio', 'records', 'label', 'sello',
  'booking', 'festival', 'agencia', 'agency',
  'revista', 'magazine', 'news', 'media', 'press',
  'frases', 'quotes', 'frasesde', 'memes',
  'official_merch', 'merch', 'fans_de', 'fanpage'
];

const preFiltered = limited.filter(u =>
  !USERNAME_EXCLUDE.some(kw => u.toLowerCase().includes(kw))
);

console.log('Posts procesados: ' + rawCount);
console.log('Usernames únicos: ' + usernames.length);
console.log('Después de límite (' + maxToEnrich + '): ' + limited.length);
console.log('Después de pre-filtro username: ' + preFiltered.length);
console.log('Ahorrado en Profile Scraper: ' + (limited.length - preFiltered.length) + ' llamadas');

if (preFiltered.length === 0) {
  throw new Error('No quedaron usernames tras el pre-filtro. Revisar hashtags o ampliar el límite.');
}

return [{
  json: {
    usernames: preFiltered,
    APIFY_TOKEN: cfg.APIFY_TOKEN,
    MIN_FOLLOWERS: cfg.MIN_FOLLOWERS,
    MAX_FOLLOWERS: cfg.MAX_FOLLOWERS,
    stats: {
      raw_posts: rawCount,
      unique_users: usernames.length,
      after_limit: limited.length,
      pre_filtered: preFiltered.length,
      saved_calls: limited.length - preFiltered.length
    }
  }
}];

const STRONG_BAND_KW = [
  'banda', 'band', 'grupo musical', 'grupo de rock', 'grupo de metal',
  'grupo de blues', 'grupo de jazz', 'grupo de punk', 'grupo de folk',
  'somos una banda', 'somos un grupo', 'cuarteto de rock', 'trío de rock',
  'power trio', 'rock band', 'metal band', 'punk band', 'jazz band',
  'en vivo desde', 'próximos shows', 'próximo show', 'fecha de show',
  'nueva fecha', 'nuevas fechas', 'este viernes en', 'este sábado en',
  'tocamos en', 'tocando en', 'our band', 'nuestra banda', 'nuestro grupo'
];

const RELEASE_KW = [
  'nuevo ep', 'nuevo album', 'nuevo álbum', 'nuevo single',
  'new ep', 'new album', 'new single', 'out now', 'ya disponible',
  'escuchalo en', 'escúchalo en', 'streamea', 'en spotify', 'en todas las plataformas',
  'primer disco', 'segundo disco', 'tercer disco'
];

const GENRE_KW = [
  'rock', 'metal', 'jazz', 'blues', 'punk', 'folk', 'indie',
  'grunge', 'hardcore', 'shoegaze', 'postpunk', 'post-punk',
  'progresivo', 'psicodélico', 'garage', 'darkwave', 'stoner', 'doom'
];

const MEMBER_KW = [
  'guitarrista', 'baterista', 'bajista', 'cantante', 'vocalista',
  'guitarist', 'drummer', 'bassist', 'vocalist', 'tecladista',
  'compositor', 'songwriter'
];

const GOOD_CATEGORIES = [
  'musician', 'band', 'music', 'musico', 'músico',
  'banda', 'artista', 'artist', 'rock', 'metal', 'jazz',
  'blues', 'punk', 'indie', 'cantante', 'singer', 'composer',
  'compositor', 'dj', 'grupo musical'
];

const BAD_CATEGORIES = [
  'radio', 'emisora', 'clothing', 'ropa', 'fashion', 'moda',
  'bar', 'pub', 'restaurant', 'venue', 'recording studio',
  'estudio', 'label', 'record', 'sello', 'booking', 'agency',
  'agencia', 'media', 'news', 'noticias', 'blogger', 'blog',
  'tienda', 'shop', 'store', 'brand', 'marca', 'quotes',
  'frases', 'memes', 'humor', 'community', 'comunidad',
  'festival', 'promoter', 'promotora', 'magazine', 'revista'
];

const HARD_EXCLUDE_BIO = [
  'tienda', 'shop', 'store', 'ropa', 'indumentaria', 'camisetas', 'remeras',
  'envíos', 'envios', 'stock', 'talle', 'talles', 'compras', 'pedidos',
  'descuento', 'precio', 'mayorista', 'minorista', 'local de', 'boutique',
  'accesorios', 'calzado', 'zapatillas', 'colección', 'coleccion',
  'bar ', 'pub ', 'boliche', 'cervecería', 'cerveceria', 'tragos',
  'gastronomía', 'gastronomia', 'reservas al', 'reserva tu mesa',
  'cocina', 'restaurante', 'parrilla', 'capacidad',
  'estudio de grabación', 'estudio de grabacion', 'grabación profesional',
  'mezcla y masterización', 'productor musical', 'produccion musical',
  'alquiler de sala', 'sala de ensayo',
  'booking', 'management', 'agencia de', 'promotora', 'sello discográfico',
  'sello independiente', 'discográfica', 'revista', 'portal de música',
  'periodismo', 'cobertura', 'entradas', 'ticketing', 'festival de',
  'trap', 'reggaeton', 'regueton', 'reggaetón', 'cumbia', 'bachata',
  'merengue', 'dembow', 'urbano', 'rap', 'perreo', 'salsa', 'mambo',
  'vallenato', 'corrido', 'norteño', 'banda sinaloense',
  'frases de', 'quotes de', 'frase del día', 'pensamientos de'
];

const EXCLUDE_USERNAME = [
  'shop', 'store', 'tienda', 'ropa', 'indumentaria', 'records_label',
  'booking', 'festival', 'bar_rock', 'pub_rock', 'estudio_de',
  'studio_oficial', 'revista', 'news', 'media', 'official_merch', 'merch',
  'frases', 'quotes', 'frasesde'
];

const cfg = $('⚙️ Config + Override Dashboard').first().json;
const MIN = parseInt(cfg.MIN_FOLLOWERS) || 300;
const MAX = parseInt(cfg.MAX_FOLLOWERS) || 500000;
const today = new Date().toISOString().split('T')[0];

const items = $input.all();
const valid = [];
let stats = { private: 0, followers: 0, badCategory: 0, hardExcludeBio: 0, usernameExclude: 0, noEvidence: 0 };

for (const item of items) {
  const data = item.json;
  const profiles = Array.isArray(data) ? data : [data];

  for (const p of profiles) {
    if (!p || !p.username) continue;

    const bio = (p.biography || p.bio || '').toLowerCase();
    const username = (p.username || '').toLowerCase();
    const category = (p.businessCategoryName || '').toLowerCase();
    const followers = p.followersCount || p.followers || 0;
    const isPrivate = p.private || p.isPrivate || false;

    if (isPrivate) { stats.private++; continue; }
    if (followers < MIN || followers > MAX) { stats.followers++; continue; }
    if (BAD_CATEGORIES.some(kw => category.includes(kw))) { stats.badCategory++; continue; }
    if (HARD_EXCLUDE_BIO.some(kw => bio.includes(kw))) { stats.hardExcludeBio++; continue; }
    if (EXCLUDE_USERNAME.some(kw => username.includes(kw))) { stats.usernameExclude++; continue; }

    let score = 0;
    if (GOOD_CATEGORIES.some(kw => category.includes(kw))) score += 4;
    if (STRONG_BAND_KW.some(kw => bio.includes(kw))) score += 3;
    if (RELEASE_KW.some(kw => bio.includes(kw))) score += 2;
    if (MEMBER_KW.some(kw => bio.includes(kw))) score += 2;
    if (GENRE_KW.some(kw => bio.includes(kw))) score += 1;
    if (GENRE_KW.some(kw => username.includes(kw))) score += 1;

    if (score < 2) { stats.noEvidence++; continue; }

    const recentTags = (p.latestPosts || []).flatMap(post => post.hashtags || []).join(' ').toLowerCase();
    let country = 'LATAM';
    if (recentTags.includes('argentina') || recentTags.includes('buenosaires')) country = 'ARG';
    else if (recentTags.includes('chile') || recentTags.includes('santiago')) country = 'CHI';
    else if (recentTags.includes('mexico') || recentTags.includes('cdmx')) country = 'MEX';
    else if (recentTags.includes('colombia') || recentTags.includes('bogota')) country = 'COL';
    else if (recentTags.includes('uruguay') || recentTags.includes('montevideo')) country = 'URU';
    else if (recentTags.includes('peru') || recentTags.includes('lima')) country = 'PER';
    else if (recentTags.includes('venezuela') || recentTags.includes('caracas')) country = 'VEN';
    else if (recentTags.includes('ecuador') || recentTags.includes('quito')) country = 'ECU';
    else if (recentTags.includes('bolivia')) country = 'BOL';
    else if (recentTags.includes('paraguay')) country = 'PAR';

    valid.push({
      username: p.username,
      profile_url: `https://www.instagram.com/${p.username}`,
      full_name: p.fullName || '',
      bio: (p.biography || p.bio || '').substring(0, 400),
      followers,
      following: p.followsCount || 0,
      posts_count: p.postsCount || 0,
      website: p.externalUrl || '',
      ig_category: p.businessCategoryName || '',
      filter_score: score,
      country_tag: country,
      status: 'pending',
      date_added: today,
      dm_sent_date: '',
      notes: ''
    });
  }
}

console.log(`\n📊 FILTRO ESTRICTO:`);
console.log(`  ✅ Bandas válidas: ${valid.length}`);
console.log(`  🔒 Privadas: ${stats.private}`);
console.log(`  📉 Followers fuera de rango: ${stats.followers}`);
console.log(`  🏷️ Categoría IG excluida: ${stats.badCategory}`);
console.log(`  🚫 Bio excluida: ${stats.hardExcludeBio}`);
console.log(`  🔤 Username excluido: ${stats.usernameExclude}`);
console.log(`  ❓ Sin evidencia (score < 2): ${stats.noEvidence}`);

if (valid.length === 0) {
  console.log('⚠️ Sin resultados.');
  return [];
}

return valid.map(b => ({ json: b }));

const cfg = $('⚙️ Config + Override Dashboard').first().json;
const batchNode = $('🎯 Seleccionar Batch').first().json;

console.log('\n========================================');
console.log('✅ RUN COMPLETADO');
console.log('========================================');
console.log(`📋 Hashtags procesados: ${batchNode.hashtags_batch.join(', ')}`);
console.log(`🔢 Próximo HASHTAG_OFFSET a usar: ${batchNode.next_offset}`);
console.log(`💡 Cambia HASHTAG_OFFSET a ${batchNode.next_offset} para el próximo run`);
console.log('========================================');

return [{
  json: {
    status: 'completed',
    hashtags_used: batchNode.hashtags_batch,
    next_offset: batchNode.next_offset,
    message: `Próximo run: cambia HASHTAG_OFFSET a ${batchNode.next_offset}`
  }
}];
